import React, {

  useEffect,
  useState

} from 'react';

import ResumeService from '../services/ResumeService';

function AllResumes() {

  const [resumes, setResumes] = useState([]);

  // ================= LOAD RESUMES =================

  useEffect(() => {

    fetchResumes();

  }, []);

  const fetchResumes = async () => {

    try {

      const response =
        await ResumeService.getAllResumes();

      console.log(
        'All Resumes:',
        response.data
      );

      setResumes(response.data);

    } catch (error) {

      console.log(error);

      alert(
        'Failed To Load Resumes'
      );
    }
  };

  // ================= DELETE =================

  const deleteResume = async (id) => {

    try {

      await ResumeService.deleteResume(id);

      alert(
        'Resume Deleted Successfully'
      );

      fetchResumes();

    } catch (error) {

      console.log(error);

      alert(
        'Delete Failed'
      );
    }
  };

  return (

    <div className="container mt-5 mb-5">

      <h1 className="mb-4">

        All Resumes

      </h1>

      {

        resumes.length === 0 ? (

          <h4>No Resume Found</h4>

        ) : (

          resumes.map((resume) => (

            <div
              className="card shadow mb-4 p-4"
              key={resume.id}
            >

              <div className="row">

                <div className="col-md-3">

                  {

                    resume.profileImage && (

                      <img
                        src={resume.profileImage}
                        alt="Profile"
                        className="img-fluid rounded-circle"
                        style={{

                          width: '150px',
                          height: '150px',
                          objectFit: 'cover'

                        }}
                      />

                    )
                  }

                </div>

                <div className="col-md-9">

                  <h3>

                    {resume.fullName}

                  </h3>

                  <p>

                    <strong>Email:</strong>

                    {' '}

                    {resume.email}

                  </p>

                  <p>

                    <strong>Phone:</strong>

                    {' '}

                    {resume.phone}

                  </p>

                  <p>

                    <strong>Skills:</strong>

                    {' '}

                    {resume.skills}

                  </p>

                  <p>

                    <strong>Summary:</strong>

                    {' '}

                    {resume.summary}

                  </p>

                  <button
                    className="btn btn-danger mt-2"
                    onClick={() =>
                      deleteResume(
                        resume.id
                      )
                    }
                  >

                    Delete

                  </button>

                </div>

              </div>

            </div>

          ))
        )
      }

    </div>
  );
}

export default AllResumes;
